      expect(mockPrisma.$transaction).toHaveBeenCalled();

      // Should save all results
      expect(mockPrisma.sessionCategories.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({ session_id: 1 }),
          expect.objectContaining({ session_id: 1 }),
