        },
        attributeContext: {
          emailId: 'msg-001',
          urgency: 'low',
          domains: ['chase.com'],
          structuralPatterns: [],
          temporalSignals: [],
          detectionMetadata: {},
          influenceApplications: [],
        },
        processedAt: new Date('2025-01-01T10:05:00Z'),
        processingDurationMs: 5000,
